# beLab-edu — R コード生成アシスタント
#
# 学生は GUI で操作 → 生成された R コードをコピー → Colab に貼って実行．
# 「ボタンを押すと R 構文が見える」ことが学習の核．
#
# Deploy via shinylive:
#   shinylive::export("inst/edu", "docs/edu")
# → docs/edu/ を GitHub Pages にアップ → 学生は単一 URL でアクセス
#
# Lightweight deps: shiny, bslib, ggplot2, dplyr, DT （shinylive 50MB 内）

suppressPackageStartupMessages({
  library(shiny); library(bslib); library(ggplot2); library(dplyr); library(DT)
})

# ---- Built-in datasets for teaching ---------------------------------------
# Small synthetic survey dataset matching the lecture-style column structure
# (性別 / 居住エリア / 利用頻度 / 年齢) — useful for クロス集計 and t-test 演習.
.make_survey_demo <- function() {
  set.seed(42)
  n <- 240
  sex <- sample(c("男性", "女性"), n, replace = TRUE, prob = c(0.48, 0.52))
  area <- sample(c("都市部", "郊外", "地方"), n, replace = TRUE,
                  prob = c(0.45, 0.35, 0.20))
  # 性別と「スーパー利用頻度」に弱い関連を入れる
  super_freq <- vapply(sex, function(s)
    if (s == "女性")
      sample(c("高頻度","中頻度","低頻度"), 1, prob = c(0.50, 0.32, 0.18))
    else
      sample(c("高頻度","中頻度","低頻度"), 1, prob = c(0.30, 0.40, 0.30)),
    character(1))
  conv_freq <- sample(c("高頻度","中頻度","低頻度"), n, replace = TRUE,
                       prob = c(0.35, 0.40, 0.25))
  age <- sample(20:69, n, replace = TRUE)
  spend <- round(rnorm(n,
            mean = ifelse(super_freq == "高頻度", 25000,
                   ifelse(super_freq == "中頻度", 18000, 10000)),
            sd = 5000))
  data.frame(性別 = sex, 居住エリア = area,
             スーパー利用 = super_freq, コンビニ利用 = conv_freq,
             年齢 = age, 月額食費 = spend,
             stringsAsFactors = FALSE)
}

edu_datasets <- list(
  "survey (アンケート)" = .make_survey_demo(),
  "iris (アヤメ)"      = iris,
  "mtcars (車)"        = mtcars,
  "airquality (大気)"  = airquality,
  "diamonds (先頭1000行)" = ggplot2::diamonds[1:1000, ]
)

# ---- Helpers --------------------------------------------------------------
# Keep an accumulator of generated R code across the session
# Plain HTML button (NOT actionButton) — Shiny would overwrite onclick.
# Clicking copies the rendered <pre> contents to clipboard via Clipboard API.
copy_btn <- function(target_id) {
  tags$button(
    type = "button",
    class = "btn btn-sm btn-outline-primary",
    onclick = sprintf(
      paste0("var el=document.getElementById('%s');",
             "var t=el?(el.innerText||el.textContent):'';",
             "navigator.clipboard.writeText(t).then(",
             "function(){var b=event.target;var orig=b.innerText;",
             "b.innerText='✓ コピー済み';",
             "setTimeout(function(){b.innerText=orig;},1500);})"),
      target_id),
    HTML("\U0001F4CB コピー"))
}

code_card <- function(header, code_id, helper_text = NULL) {
  card(
    card_header(
      div(style = "display:flex;justify-content:space-between;align-items:center;",
        span(strong("R コード — "), header,
             tags$small(class = "text-muted",
                        style = "margin-left:.6em; font-weight: 400;",
                        HTML("\U2192 \U0001F4CB \U2192 Google Colab で実行"))),
        copy_btn(code_id)
      )
    ),
    if (!is.null(helper_text)) p(class = "small text-muted", helper_text),
    verbatimTextOutput(code_id)
  )
}

# 各タブの上部に置く「何の分析？何のため？」の説明ブロック
purpose_block <- function(id, title, what, when, output_hint = NULL) {
  div(id = id,
      class = "small mb-2",
      style = paste("border-left: 4px solid #5BC0DE;",
                     "background: #F0FBFE;",
                     "padding: 10px 14px;",
                     "border-radius: 0 6px 6px 0;"),
      tags$div(style = "font-weight: 700; color: #1F5673; margin-bottom: 4px;",
               HTML(paste0("\U0001F4A1 ", title))),
      tags$div(style = "margin-bottom: 4px;",
               tags$strong("何の分析？"), " ", HTML(what)),
      tags$div(style = "margin-bottom: 4px;",
               tags$strong("何のため？"), " ", HTML(when)),
      if (!is.null(output_hint))
        tags$div(tags$strong("出力の読み方"), " ", HTML(output_hint))
  )
}

# ---- intro.js (CDN) — guided tutorials ------------------------------------
tour_head <- tags$head(
  tags$link(rel = "stylesheet",
    href = "https://cdn.jsdelivr.net/npm/intro.js@7.2.0/minified/introjs.min.css"),
  tags$script(
    src = "https://cdn.jsdelivr.net/npm/intro.js@7.2.0/minified/intro.min.js"),
  tags$script(HTML(
'Shiny.addCustomMessageHandler("startTour", function(config) {
  var steps = config.steps || [];

  // ---------- helpers ----------------------------------------------------
  function resolveElement(sel) {
    if (!sel) return null;
    var el = null;
    try { el = document.querySelector(sel); } catch (e) { return null; }
    if (!el) return null;
    var tag = (el.tagName || "").toUpperCase();
    if (tag === "SELECT" || tag === "INPUT" || tag === "TEXTAREA") {
      var c = el.closest(".shiny-input-container");
      if (c) return c;
    }
    return el;
  }

  function selectTab(value) {
    return new Promise(function(resolve) {
      var link = document.querySelector(
        \'a.nav-link[data-value="\' + value + \'"]\');
      if (link && !link.classList.contains("active")) {
        link.click();
        setTimeout(resolve, 420);
      } else { resolve(); }
    });
  }

  // Bootstrap accordion auto-expand: if the target sits inside a collapsed
  // .accordion-collapse, click its toggle button and wait for the transition.
  function expandAncestors(el) {
    if (!el) return Promise.resolve();
    var collapsed = null;
    var cursor = el;
    while (cursor && cursor !== document.body) {
      if (cursor.classList && cursor.classList.contains("accordion-collapse") &&
          !cursor.classList.contains("show")) {
        collapsed = cursor; break;
      }
      cursor = cursor.parentNode;
    }
    if (!collapsed) return Promise.resolve();
    var pid = collapsed.id;
    var btn = pid
      ? document.querySelector(\'[data-bs-target="#\' + pid + \'"]\')
      : null;
    if (!btn) return Promise.resolve();
    btn.click();
    // Bootstrap collapse animation ~350ms; recurse for nested accordions.
    return new Promise(function(resolve) {
      setTimeout(function() {
        expandAncestors(el.parentNode).then(resolve);
      }, 450);
    });
  }

  // Walk up every scrollable ancestor and center the element in each.
  // This handles bslib sidebar (overflow:auto) + nested accordions.
  function getScrollableAncestor(el) {
    var p = el.parentNode;
    while (p && p !== document.body) {
      var st = window.getComputedStyle(p);
      if ((st.overflowY === "auto" || st.overflowY === "scroll") &&
          p.scrollHeight > p.clientHeight) return p;
      p = p.parentNode;
    }
    return null;
  }
  function scrollAllAncestorsIntoView(el) {
    if (!el) return;
    var current = el;
    var safety = 5;
    while (current && safety-- > 0) {
      var ancestor = getScrollableAncestor(current);
      if (!ancestor) break;
      var rect = el.getBoundingClientRect();
      var aRect = ancestor.getBoundingClientRect();
      // Position to center the element in the scrollable ancestor.
      var offset = (rect.top - aRect.top)
                 - (aRect.height / 2 - rect.height / 2);
      ancestor.scrollTop = Math.max(0, ancestor.scrollTop + offset);
      current = ancestor;
    }
    // Final fallback: page-level scroll
    try { el.scrollIntoView({block: "center", behavior: "auto"}); } catch (e) {}
  }

  // Wait two animation frames so layout/scroll/paint are settled.
  function waitForLayout() {
    return new Promise(function(resolve) {
      requestAnimationFrame(function() {
        requestAnimationFrame(resolve);
      });
    });
  }
  function safeRefresh(intro) {
    if (typeof intro.refresh === "function") {
      try { intro.refresh(); } catch (e) {}
    }
  }

  // ---------- intro.js setup --------------------------------------------
  var intro = window.introJs ? window.introJs() : null;
  if (!intro) { console.error("intro.js not loaded"); return; }
  var introSteps = steps.map(function(s) {
    var o = {intro: s.intro};
    var resolved = null;
    if (s.element) {
      resolved = resolveElement(s.element);
      o.element = resolved || s.element;
    }
    if (resolved && resolved.querySelector && resolved.querySelector("select")) {
      o.position = s.position || "right";
    } else if (s.position) {
      o.position = s.position;
    }
    return o;
  });
  intro.setOptions({
    steps: introSteps,
    nextLabel: "次へ →", prevLabel: "← 戻る",
    skipLabel: "✕", doneLabel: "完了",
    showStepNumbers: true, showProgress: true,
    // We do scrolling ourselves (multi-ancestor) — disable intro.js builtin.
    scrollToElement: false,
    overlayOpacity: 0.5, exitOnOverlayClick: false,
    tooltipClass: "belab-tour",
    positionPrecedence: ["right", "top", "left", "bottom"]
  });

  intro.onbeforechange(function() {
    var i = intro._currentStep, step = steps[i];
    return Promise.resolve()
      .then(function() {
        if (step && step.tab) return selectTab(step.tab);
      })
      .then(function() {
        if (!step) return;
        if (!step.element) {
          // No element step (intro-only) — still settle layout before paint.
          return waitForLayout().then(function() { safeRefresh(intro); });
        }
        var resolved = resolveElement(step.element);
        if (!resolved) return;
        return expandAncestors(resolved).then(function() {
          // DOM may have mutated during accordion expand → re-resolve.
          var r2 = resolveElement(step.element);
          if (!r2) return;
          intro._introItems[i].element = r2;
          // Phase 1: scroll all scrollable ancestors so r2 is centered.
          scrollAllAncestorsIntoView(r2);
          // Phase 2: wait for scroll/layout to settle, then refresh.
          return waitForLayout()
            .then(function() {
              safeRefresh(intro);
              // Phase 3: one more frame for late reflows (bslib transitions).
              return waitForLayout();
            })
            .then(function() {
              // Re-scroll in case accordion-open pushed things around again.
              var r3 = resolveElement(step.element);
              if (r3) {
                intro._introItems[i].element = r3;
                scrollAllAncestorsIntoView(r3);
              }
              return waitForLayout();
            })
            .then(function() { safeRefresh(intro); });
        });
      });
  });

  // Initial start: wait two frames after the 320ms timeout so the first
  // step\'s element is laid out before intro.js measures it.
  setTimeout(function() {
    waitForLayout().then(function() { intro.start(); });
  }, 320);
});

// Auto-launch welcome tour on first visit. localStorage flag prevents
// re-firing on subsequent visits.  Bump the version number to re-show
// for everyone (e.g. when the welcome content is updated).
$(document).on("shiny:connected", function() {
  try {
    if (!localStorage.getItem("belab_seen_intro_v1")) {
      setTimeout(function() {
        var link = document.getElementById("tour_welcome");
        if (link) {
          link.click();
          localStorage.setItem("belab_seen_intro_v1", "1");
        }
      }, 1500);
    }
  } catch (e) {}
});')),
  tags$style(HTML(
"  .belab-tour { min-width: 360px; max-width: 520px; }
   .belab-tour .introjs-tooltiptext { font-size: 14px; line-height: 1.6; }
   .introjs-helperLayer { box-shadow: 0 0 0 1000px rgba(0,0,0,0.5),
                                       0 0 6px 2px #EB77CB inset !important; }
   .introjs-button { font-size: 13px; padding: 6px 12px; }

   /* Ensure selectize/native dropdown menus float ABOVE the intro overlay
      so students can actually click the options.  intro.js helperLayer is
      9999998; we lift dropdowns above that. */
   .selectize-dropdown,
   .selectize-control.single .selectize-dropdown,
   .dropdown-menu.show          { z-index: 99999999 !important; }
   /* When a step highlights a select, give the whole input container some
      breathing room so the tooltip arrow doesn\'t sit on top of the widget. */
   .introjs-showElement .selectize-control { z-index: 99999999 !important; }
"))
)

# ---- UI -------------------------------------------------------------------
ui <- page_navbar(
  id = "main_nav",
  title = "beLab-edu",
  theme = bs_theme(version = 5, bootswatch = "flatly",
                    primary = "#1976D2", "navbar-bg" = "#EB77CB"),
  fillable = TRUE,
  header = tour_head,

  # ---- ① Data -----------------------------------------------------------
  nav_panel("① データ", value = "tab_data",
    layout_sidebar(sidebar = sidebar(width = 340,
      h4("データを読み込む"),
      radioButtons("data_source", "データの取り方",
        choices = c("組込みデータ（iris など）"   = "builtin",
                    "CSV ファイルをアップロード"  = "csv_upload",
                    "URL から CSV"                 = "csv_url",
                    "Google ドライブから（Colab 用）" = "csv_drive"),
        selected = "builtin"),
      conditionalPanel("input.data_source == 'builtin'",
        selectInput("ds", "組込みデータ",
          choices = names(edu_datasets))),
      conditionalPanel("input.data_source == 'csv_upload'",
        fileInput("csv_file", "CSV ファイルを選択",
                  accept = c(".csv","text/csv","text/plain"),
                  buttonLabel = "ファイル選択",
                  placeholder = "未選択"),
        numericInput("csv_skip",
                      "ヘッダーより前にスキップする行数 (SSDSE は 1)",
                      value = 0, min = 0, max = 10, step = 1),
        helpText("文字化けする場合は，UTF-8 → CP932 → Shift-JIS の順で",
                  "自動的に試します．")),
      conditionalPanel("input.data_source == 'csv_url'",
        textInput("csv_url",  "CSV の URL",
                  value = "https://example.com/data.csv"),
        actionButton("fetch_url", "URL から読込（プレビュー用）",
                     class = "btn-sm btn-primary"))),
      purpose_block("purpose_data",
        "① データ — 分析の出発点",
        "分析するデータを R に読み込み，<b>構造を確認</b>する．",
        "いきなり統計に進まず，まず行数・列名・型・欠損の有無を見るのが鉄則．",
        "<code>head(df)</code> で先頭6行，<code>str(df)</code> で各列の型，<code>dim(df)</code> で行数×列数を確認．"),
      code_card("データ読込", "code_data",
        "ここに表示される R コードを Colab に貼り付ければ，同じデータが読み込める．"),
      card(card_header("読み込んだデータ（プレビュー）"),
        textOutput("data_summary"),
        DTOutput("preview")))),

  # ---- ② Wrangle --------------------------------------------------------
  nav_panel("② 整形", value = "tab_wrangle",
    layout_sidebar(sidebar = sidebar(width = 340,
      h4("整形（dplyr）"),
      helpText("操作を選ぶと R コードが下に出る．"),
      accordion(open = "基本操作",
        accordion_panel("基本操作",
          checkboxGroupInput("wrangle_ops",
            "実行する操作（複数可・上から順に適用）",
            choices = c("filter（条件で行抽出）"          = "filter",
                        "drop_na（欠損行を除外・第3講）"  = "dropna",
                        "select（列を選ぶ）"               = "select",
                        "mutate（新しい列を作る）"         = "mutate",
                        "group_by + summarise（集計）"      = "groupby",
                        "arrange（並べ替え）"               = "arrange",
                        "case_when（条件分岐）"             = "casewhen")),
          conditionalPanel("input.wrangle_ops.includes('filter')",
            textInput("filter_expr", "filter 条件",
              value = "Sepal.Length > 5")),
          conditionalPanel("input.wrangle_ops.includes('dropna')",
            textInput("dropna_col",
              "欠損を除外する列（カンマ区切り可）",
              value = "Q4_3"),
            helpText("空欄なら全列で欠損のある行を除外．",
                     "drop_na(列) と filter(!is.na(列)) は同じ意味．")),
          conditionalPanel("input.wrangle_ops.includes('select')",
            textInput("select_cols", "残す列（カンマ区切り）",
              value = "Sepal.Length, Petal.Length, Species")),
          conditionalPanel("input.wrangle_ops.includes('mutate')",
            textInput("mutate_expr", "mutate 式",
              value = "ratio = Sepal.Length / Petal.Length")),
          conditionalPanel("input.wrangle_ops.includes('groupby')",
            textInput("groupby_var", "group_by の変数",
              value = "Species"),
            textInput("summarise_expr", "summarise の中身",
              value = "mean = mean(Sepal.Length), n = n()")),
          conditionalPanel("input.wrangle_ops.includes('arrange')",
            textInput("arrange_expr", "arrange の中身",
              value = "desc(Sepal.Length)"))),
        accordion_panel("結合 join (第9講)",
          helpText("2 つのデータフレームをキーで結合する．",
                    "Colab で 2 つの df を持っている前提のコードを生成．"),
          checkboxInput("wrangle_join_on", "join のコードを生成", FALSE),
          conditionalPanel("input.wrangle_join_on == true",
            selectInput("join_type", "結合の種類",
              choices = c("left_join (左を残す・右をくっつける)" = "left",
                          "inner_join (両方にあるキーだけ)"        = "inner",
                          "full_join (両方の和集合)"               = "full",
                          "anti_join (左にあって右にないキー)"     = "anti")),
            textInput("join_left_df",  "左のデータ (R 側の変数名)",
                       value = "df"),
            textInput("join_right_df", "右のデータ (R 側の変数名)",
                       value = "df2"),
            textInput("join_by",
                       "by = ?（キーの列名．複数なら c(\"a\",\"b\")）",
                       value = "\"都道府県\""))),
        accordion_panel("\U0001F4DD 演習テンプレ",
          helpText("講義の演習問題でよく出るパターンをワンクリックで．",
                    "チェックを入れると下のコードに追加されます．"),
          checkboxInput("tpl_age_band",
            HTML("<b>年代を作る</b> (case_when・第4講 Q5 風)"), FALSE),
          checkboxInput("tpl_region",
            HTML("<b>都道府県 → 8 地方ブロック化</b> (第4講 §3)"), FALSE),
          conditionalPanel("input.tpl_region == true",
            textInput("tpl_region_col", "都道府県の列名",
                       value = "都道府県")),
          checkboxInput("tpl_tukey",
            HTML("<b>Tukey フェンスで外れ値抽出</b> (第5講 §4)"), FALSE),
          conditionalPanel("input.tpl_tukey == true",
            textInput("tpl_tukey_col", "対象の数値列",
                       value = "Q24")),
          checkboxInput("tpl_pivot_long",
            HTML("<b>pivot_longer (ワイド→ロング)</b> (第9講 §3)"), FALSE),
          conditionalPanel("input.tpl_pivot_long == true",
            textInput("tpl_pivot_cols",
                       "ロング化する列（カンマ区切り）",
                       value = "年2019, 年2022"),
            textInput("tpl_pivot_names", "names_to",
                       value = "年度"),
            textInput("tpl_pivot_values", "values_to",
                       value = "値")),
          checkboxInput("tpl_yoy",
            HTML("<b>前年比・累積成長率</b> (第9講)"), FALSE),
          conditionalPanel("input.tpl_yoy == true",
            textInput("tpl_yoy_col", "時系列の列名",
                       value = "値")),
          checkboxInput("tpl_freq_cat",
            HTML("<b>頻度を 3 カテゴリ化</b> (高/中/低・第6講 Q1 風)"), FALSE),
          conditionalPanel("input.tpl_freq_cat == true",
            textInput("tpl_freq_col", "対象列 (1〜10 の数値)",
                       value = "Q4_3")),
          checkboxInput("tpl_grep_vars",
            HTML("<b>grep で変数一覧抽出</b> (第11講・実験変数の確認)"), FALSE),
          conditionalPanel("input.tpl_grep_vars == true",
            textInput("tpl_grep_pattern", "検索パターン (正規表現)",
                       value = "imc")),
          checkboxInput("tpl_imc_rate",
            HTML("<b>IMC 正答率の計算</b> (rowwise・第13講)"), FALSE),
          checkboxInput("tpl_imc_set",
            HTML("<b>IMC 設問セット別の正答率</b> (imc1/imc2/imc3・第13講 Q3)"), FALSE),
          checkboxInput("tpl_dictator_cat",
            HTML("<b>寄付額を 3 カテゴリ化</b> (第14講 Q1)"), FALSE),
          conditionalPanel("input.tpl_dictator_cat == true",
            textInput("tpl_give_col", "寄付額の列",
                       value = "dictator.1.player.give"))))),
      purpose_block("purpose_wrangle",
        "② 整形 — データを「分析しやすい形」にする",
        "<code>filter / select / mutate / group_by / case_when</code> でデータを切り出し・加工する．",
        "「分析の8割は前処理」と言われるほど重要．新しい列の作成（年代・カテゴリ化）もここで．",
        "整形後はもう一度 <code>head()</code> で結果を確認するのが習慣．"),
      code_card("整形", "code_wrangle",
        "df を上書きしないので元データは保持される．"))),

  # ---- ③ Descriptive ----------------------------------------------------
  nav_panel("③ 記述統計", value = "tab_desc",
    layout_sidebar(sidebar = sidebar(width = 320,
      h4("記述統計"),
      selectInput("dv_desc", "変数（数値）",   choices = NULL),
      selectInput("grp_desc", "群分け（任意）",
        choices = c("(なし)" = ""), selected = ""),
      checkboxGroupInput("desc_stats", "計算する統計量",
        choices = c("平均 mean"   = "mean",
                    "標準偏差 sd" = "sd",
                    "中央値 median" = "median",
                    "最頻値 mode (table)" = "mode",
                    "最小 / 最大"   = "minmax",
                    "四分位（Q1/Q3）"   = "quart",
                    "件数 n"        = "n"),
        selected = c("mean", "sd", "n")),
      checkboxInput("desc_zscore",
        HTML("<b>z スコア (scale)</b> も計算 (第2講 Q5)"), FALSE)),
      purpose_block("purpose_desc",
        "③ 記述統計 — データの代表値とばらつきを把握",
