  code_ct <- reactive({
    if (!nzchar(input$ct_row %||% "") || !nzchar(input$ct_col %||% ""))
      return("# 行変数と列変数を選んでください")
    # Quote with back-ticks only if name contains spaces / special chars
    qcol <- function(x) if (grepl("^[A-Za-z._぀-鿿][A-Za-z0-9._぀-鿿]*$", x))
                          x else sprintf("`%s`", x)
    rn <- qcol(input$ct_row); cn <- qcol(input$ct_col)
    lines <- c(
      sprintf("# クロス集計表を作る\ntab <- table(df$%s, df$%s, useNA = \"ifany\")",
               rn, cn),
      "")
    if (isTRUE(input$ct_addmargins))
      lines <- c(lines, "addmargins(tab)  # 合計を追加")
    if ((input$ct_prop %||% "row") != "none") {
      pt_arg <- switch(input$ct_prop,
        row = "tab, margin = 1",
        col = "tab, margin = 2",
        total = "tab")
      lab <- switch(input$ct_prop,
        row = "行ごと（各行の合計が 100%）",
        col = "列ごと（各列の合計が 100%）",
        total = "全体（総合計に対する比率）")
      lines <- c(lines, sprintf("\n# 比率（%s）\nround(prop.table(%s) * 100, 1)",
                                 lab, pt_arg))
    }
    # chisq の結果を後段（V/expected/residuals）でも使うので
    # ct_chisq が外れていても，それらが ON のときは chi を作る
    need_chi <- isTRUE(input$ct_chisq) ||
                 isTRUE(input$ct_cramer) ||
                 isTRUE(input$ct_expected) ||
                 isTRUE(input$ct_residuals)
    if (need_chi)
      lines <- c(lines,
                  "\n# カイ二乗検定（独立性の検定）",
                  "# 帰無仮説 H0: 2 変数は独立（関連がない）",
                  "# p < 0.05 なら H0 を棄却 → 関連がある",
                  "chi <- chisq.test(tab)")
    if (isTRUE(input$ct_chisq))
      lines <- c(lines, "print(chi)")
    if (isTRUE(input$ct_cramer)) {
      lines <- c(lines,
                  "",
                  "# クラメールの V（連関の強さ：0-1）",
                  "# 目安: 0.1 未満=弱い  0.1-0.3=中  0.3 以上=強い",
                  "# n が大きいと p < 0.05 でも実質的な関連は弱いことがある．V で確認．",
                  "n <- sum(tab); k <- min(nrow(tab), ncol(tab))",
                  "cramer_v <- sqrt(as.numeric(chi$statistic) / (n * (k - 1)))",
                  "cat(\"Cramer's V =\", round(cramer_v, 3), \"\\n\")")
    }
    if (isTRUE(input$ct_expected)) {
      lines <- c(lines,
                  "",
                  "# 期待度数（H0 が正しい場合に各セルに期待される値・第6講 Q4）",
                  "# 期待度数 = 行合計 × 列合計 ÷ 総合計",
                  "round(chi$expected, 2)",
                  "# 期待度数 < 5 のセルがあればカイ二乗の妥当性が低下 → Fisher 検定へ",
                  "any(chi$expected < 5)")
    }
    if (isTRUE(input$ct_residuals)) {
      lines <- c(lines,
                  "",
                  "# 標準化残差 (観測 − 期待) / sqrt(期待) — 第6講 Q4",
                  "# |残差| > 2 のセルが「特に貢献している組合せ」",
                  "round(chi$residuals, 2)")
    }
    if (isTRUE(input$ct_fisher)) {
      lines <- c(lines,
                  "",
                  "# Fisher 正確検定（期待度数<5 のセルがあるとき推奨・第6講 §3）",
                  "# H0: 独立．小標本でもカイ二乗と違って近似に頼らない．",
                  "fisher.test(tab)")
    }
    if (isTRUE(input$ct_mosaic)) {
      lines <- c(lines,
                  "",
                  "# モザイクプロット (第6講 Q6) — 行%・列%を面積で可視化",
                  "# セルの大きさ = 構成比，色 = 期待からの偏差（shade=TRUE）",
                  "mosaicplot(tab, main = \"クロス集計のモザイクプロット\",",
                  "           color = TRUE, shade = TRUE, las = 1)")
    }
    paste(lines, collapse = "\n")
  })
  output$code_ct <- renderText(code_ct())

  output$ct_preview <- renderPrint({
    req(rv$df, input$ct_row, input$ct_col)
    if (!nzchar(input$ct_row) || !nzchar(input$ct_col)) return(invisible())
    tab <- table(rv$df[[input$ct_row]], rv$df[[input$ct_col]],
