  # ---- Tour trigger helper ----------------------------------------
  start_tour <- function(tour_def, init_tab = "tab_data",
                          reset_data = TRUE) {
    if (reset_data)
      updateRadioButtons(session, "data_source", selected = "builtin")
    nav_select(id = "main_nav", selected = init_tab)
    session$sendCustomMessage("startTour", tour_def)
  }

  observeEvent(input$tour_welcome, start_tour(tour_welcome,
                                                init_tab = "tab_data",
                                                reset_data = FALSE))
