  observeEvent(input$tour_extr,  start_tour(tour_extr))
  observeEvent(input$tour_grp,   start_tour(tour_grp))
  observeEvent(input$tour_viz,   start_tour(tour_viz))
  observeEvent(input$tour_ct,    start_tour(tour_crosstab))
  observeEvent(input$tour_cor,   start_tour(tour_cor))
  observeEvent(input$tour_caus,  start_tour(tour_caus))
  observeEvent(input$tour_join,  start_tour(tour_join, reset_data = FALSE))
  observeEvent(input$tour_lm,    start_tour(tour_lm))
  observeEvent(input$tour_exp1,  start_tour(tour_exp1, reset_data = FALSE))
  observeEvent(input$tour_tt,    start_tour(tour_tt))
  observeEvent(input$tour_imc,   start_tour(tour_imc,  reset_data = FALSE))
